    // AI レポートでは UnitType に関係なく言語で単位を固定
    if (isEnglish) {
      // 英語の場合は常に mph で表示
      return ValueAndUnit(value.toStringAsFixed(1), "mph");
    } else {
      // 日本語の場合は常に km/h で表示
      return ValueAndUnit(value.toStringAsFixed(1), "km/h");
    }
  }

  /// AI レポートの出力単位はリクエスト時の言語で決定される
  /// リクエスト時に en : 単位は inch
  /// リクエスト時に ja : 単位は cm
  ///
  /// この AI レポートの変化量を現在のアプリの表示単位への変換を担う関数
  static ValueAndUnit formatBreakForAIReport({
    required double value,
    required UnitType unitType,
    required String aiReportLanguage,
  }) {
    const cmToInchRatio = 0.393701;
    final isEnglish = aiReportLanguage == 'en';

    return switch ((unitType, isEnglish)) {
      (UnitType.mphInch, true) => ValueAndUnit(value.toStringAsFixed(1), "in"),
      (UnitType.mphInch, false) => ValueAndUnit((value * cmToInchRatio).toStringAsFixed(1), "in"),
      (UnitType.kmhCm, true) => ValueAndUnit((value / cmToInchRatio).toStringAsFixed(1), "cm"),
      (UnitType.kmhCm, false) => ValueAndUnit(value.toStringAsFixed(1), "cm"),
    };
  }
}
